def solve(arg1: dict) -> str:
    # Validate input
    if 'challenge_id' not in arg1 or 'response' not in arg1:
        return 'Error: Invalid input'

    challenge_id = arg1['challenge_id']
    response = arg1['response']

    # Check if challenge_id is valid
    if challenge_id != 30092513:
        return 'Error: Challenge not found'

    # Check if response is selected
    if response not in ['Yes', 'No']:
        return 'Error: No response selected'

    # Process the response
    if response == 'Yes':
        return 'Approval submitted successfully'
    elif response == 'No':
        return 'Rejection submitted successfully'

    return 'Error: Response dropdown not selectable'
